#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int first = 1;
        for(int i=1;i<=N;i+=2){
            if(!first) printf(" ");
            printf("%d", i);
            first = 0;
        }
        for(int i=2;i<=N;i+=2){
            printf(" %d", i);
        }
        if(T) printf("\n");
    }
    return 0;
}

